import{_ as e,o as r,c as t,a2 as o}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"G03: 核心員工流動率審計 - 經營審計專家報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/經營審計/2492_華新科/20260512/G03_核心員工流動率審計.md","filePath":"審計報告庫/經營審計/2492_華新科/20260512/G03_核心員工流動率審計.md"}'),i={name:"審計報告庫/經營審計/2492_華新科/20260512/G03_核心員工流動率審計.md"};function l(n,a,h,s,d,c){return r(),t("div",null,[...a[0]||(a[0]=[o('<h1 id="g03-核心員工流動率審計-經營審計專家報告" tabindex="-1">G03: 核心員工流動率審計 - 經營審計專家報告 <a class="header-anchor" href="#g03-核心員工流動率審計-經營審計專家報告" aria-label="Permalink to &quot;G03: 核心員工流動率審計 - 經營審計專家報告&quot;">​</a></h1><blockquote><p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p></blockquote><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>核心技術或研發團隊的流動率為何？公司如何留住優秀人才？是否有關鍵人才流向競爭對手的跡象？</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：華新科員工流動率缺乏公開量化數字（ESG報告未提供近兩年離職率），但R&amp;D投入穩定（營收3%/年，2024年10.28億）、6處研發中心、員工福利費用年增9.5%顯示組織韌性。人均薪資52.2萬偏低於同業均值，有被國巨等對手挖角之風險。</li><li><strong>風險評級</strong>：中</li><li><strong>數據時效</strong>：根據截至2026年5月12日最新公開數據</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p><strong>B+（持平偏優）</strong>：2024年員工福利費用75.91億（較2023年69.30億年增9.5%），研發費用10.28億（穩定佔營收約2.7%）。綜合各來源推算集團員工人數約6,000-8,600人（合併涵蓋PSA各子公司），人均福利費用約9-12萬/月/人，屬製造業中位。非主管全時員工薪資中位數59.5萬/年（2023年），低於國巨同職級（推估約70-80萬）。HCROI估算：(稅後淨利11.95億+員工福利75.91億)/員工福利75.91億=1.16倍，偏低反映被動元件屬資本密集產業特性，非人力密集。總體人力資本效率處於行業中等水位，研發人員穩定但受薪資競爭力制約。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="_1-人力結構與薪酬競爭力" tabindex="-1">1. 人力結構與薪酬競爭力 <a class="header-anchor" href="#_1-人力結構與薪酬競爭力" aria-label="Permalink to &quot;1. 人力結構與薪酬競爭力&quot;">​</a></h3><p>華新科集團員工福利費用2024年75.91億，年增9.5%。非主管全時員工中位數59.5萬/年，對比國巨70-80萬偏低約20-30%。薪酬中位數僅反映台灣母體，PSA群體人數口徑差異大。</p><h3 id="_2-研發穩定性與留才機制" tabindex="-1">2. 研發穩定性與留才機制 <a class="header-anchor" href="#_2-研發穩定性與留才機制" aria-label="Permalink to &quot;2. 研發穩定性與留才機制&quot;">​</a></h3><p>華新科全球6處研發中心（台/中/日），每年研發投入約營收3%。留才措施含年終三節、盈餘分紅、股票配股及退休金制度。但薪酬保守，高階AI/車用研發人才吸引力不足。</p><h3 id="_3-關鍵人才流失風險" tabindex="-1">3. 關鍵人才流失風險 <a class="header-anchor" href="#_3-關鍵人才流失風險" aria-label="Permalink to &quot;3. 關鍵人才流失風險&quot;">​</a></h3><p>無證據顯示核心團隊大量離職或流向對手國巨。2022-2026年未見重大跳槽或競業訴訟報導。潛在風險：薪資52.2萬顯著低於國巨；總經理層級輪調期間中高階主管或因不確定性另尋機會；Kamaya技術團隊整合度資料不足。</p><h3 id="_4-hcroi量化分析" tabindex="-1">4. HCROI量化分析 <a class="header-anchor" href="#_4-hcroi量化分析" aria-label="Permalink to &quot;4. HCROI量化分析&quot;">​</a></h3><p>HCROI=(稅後淨利+員工福利)/員工福利：2024年1.16倍、2023年約0.98倍，反映效率改善。低於服務業常態但符合被動元件資本密集特性。</p><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><h3 id="🔴-空方觀點-利空風險" tabindex="-1">🔴 空方觀點（利空風險） <a class="header-anchor" href="#🔴-空方觀點-利空風險" aria-label="Permalink to &quot;🔴 空方觀點（利空風險）&quot;">​</a></h3><ol><li><strong>薪資競爭力明顯落後同業</strong>：非主管中位數59.5萬/年，對比國巨同級約70-80萬/年，差距20-30%。若AI/車用需求爆發導致人才爭奪加劇，華新科中高階R&amp;D人員可能被國巨、台達電等高薪對手收割。</li><li><strong>離職率資料不透明</strong>：ESG永續報告書未主動揭露近兩年員工離職率數據（同業國巨於CSR報告有揭露）。資料不透明本身即為弱訊號——若數字好看通常會主動公布，不公布暗示流動率可能偏高。</li></ol><h3 id="🟢-多方觀點-機會可能性" tabindex="-1">🟢 多方觀點（機會可能性） <a class="header-anchor" href="#🟢-多方觀點-機會可能性" aria-label="Permalink to &quot;🟢 多方觀點（機會可能性）&quot;">​</a></h3><ol><li><strong>員工福利費用YoY+9.5%顯示留才投資加大</strong>：2024年75.91億較2023年69.30億成長9.5%，顯著高於營收年增率（約5%），反映公司正透過加薪/分紅來提升留任率。員工現金酬勞從4,920萬增至7,645萬（+55%），增幅顯著。</li><li><strong>多國布局降低單點人才風險</strong>：6處研發中心跨台灣、中國、日本，非單一據點。日本Kamaya團隊技術底蘊深厚，且被整合已近20年，不易被整批挖角。全球50家分銷商體系的通路人力具高行業經驗價值。</li></ol><h3 id="⚖️-綜合權衡" tabindex="-1">⚖️ 綜合權衡 <a class="header-anchor" href="#⚖️-綜合權衡" aria-label="Permalink to &quot;⚖️ 綜合權衡&quot;">​</a></h3><p>華新科人力資本管理屬穩健保守型：留才措施完善但薪資不具攻擊性。當前AI伺服器動能帶動營收成長（2026年1-4月YoY+15.8%），若未同步提升薪酬競爭力，2026-2027年可能是核心工程師向高薪同業流失的高峰期。建議關注2025-2026年ESG報告是否主動揭露離職率數字作為觀察指標。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li><strong>年報PDF</strong>：2024 Q4合併財報第66頁（員工福利費用）、第9頁（研發費用）</li><li><strong>web_search</strong>：華新科 2492 員工人數 薪資 （Goodjob/EMIS綜合）</li><li><strong>web_search</strong>：華新科 研發人員 人數 （Digitimes等綜合）</li><li><strong>web_search</strong>：華新科 ESG/永續報告書 （Sustaihub等）</li><li><strong>FinMind</strong>：TaiwanStockFinancialStatements（stock_id=2492, 2022-2025）</li></ul>',26)])])}const b=e(i,[["render",l]]);export{u as __pageData,b as default};
